#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char A[100005], B[100005];
        scanf("%s",A);
        scanf("%s",B);
        int need[26]={0};
        for(int i=0;i<N;i++) if(A[i]!=B[i]) need[B[i]-'a']=1;
        int ans=0; for(int i=0;i<26;i++) ans+=need[i];
        printf("%d\n",ans);
    }
    return 0;
}

